import { ORDINAL_DATATYPE } from '../core/datatype-constants';
import { d3_set } from '../core/d3-constants';

export function fetchForColorDomainParser(datatype) {
    return d3_set(['extremes', 'sortedRanges', 'filteredStops', 'min', 'max']);
}

export function fetchForColorRangeParser(datatype) {
    return d3_set(['colorRanges', 'mapDistinctRanges', 'mapArrayRanges']);
}

export function fetchForSizdDomainParser(datatype) {
    return datatype === ORDINAL_DATATYPE ? d3_set(['categories']) : d3_set(['extremes']);
}

export function fetchForShapeDomainParser(datatype) {
    return datatype === ORDINAL_DATATYPE ? d3_set(['categories']) : d3_set(['extremes']);
}
